import{_ as t,o as i,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"15. Individual Flexibility Arrangements","description":"","frontmatter":{"title":"15. Individual Flexibility Arrangements","eba":"Medical Specialists 2022-2026","topics":["flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/consultation-disputes/15-individual-flexibility-arrangements.md","filePath":"ebas/medical-specialists/consultation-disputes/15-individual-flexibility-arrangements.md"}'),a={name:"ebas/medical-specialists/consultation-disputes/15-individual-flexibility-arrangements.md"};function o(s,e,l,d,g,h){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_15-individual-flexibility-arrangements" tabindex="-1">15. Individual Flexibility Arrangements <a class="header-anchor" href="#_15-individual-flexibility-arrangements" aria-label="Permalink to &quot;15. Individual Flexibility Arrangements&quot;">​</a></h1><p><strong>15.1</strong> A Doctor and the Health Service may enter into an individual flexibility arrangement under this clause that varies the effect of certain terms of this Agreement in order to meet the genuine needs of the Doctor and the Health Service. An individual flexibility arrangement must:</p><p><strong>(a)</strong> be genuinely agreed to by the Doctor and Health Service; and</p><p><strong>(b)</strong> not contravene any law.</p><p><strong>15.2</strong> An individual flexibility arrangement must be about arrangements for when hours are worked.</p><p><strong>15.3</strong> A Doctor may nominate a representative to assist in negotiations for an individual flexibility arrangement.</p><p><strong>15.4</strong> The Health Service must ensure that any individual flexibility arrangement will result in the Doctor being better off overall than the Doctor would have been if no individual flexibility arrangement was made.</p><p><strong>15.5</strong> The Health Service must ensure that an individual flexibility arrangement is in writing and signed by the Doctor and Health Service (and, if the Doctor is under 18 years of age, by the Doctor’s parent or guardian), and that it is not required to be approved or consented to by any other person.</p><p><strong>15.6</strong> The Health Service must give a copy of the individual flexibility arrangement to the Doctor within 14 days after it is agreed.</p><p><strong>15.7</strong> The Health Service must ensure that any individual flexibility arrangement sets out:</p><p><strong>(a)</strong> the terms of this Agreement that will be varied by the arrangement;</p><p><strong>(b)</strong> how the arrangement will vary the effect of the terms;</p><p><strong>(c)</strong> how the Doctor will be better off overall in relation to the terms and conditions of his or her employment as a result of the arrangement; and</p><p><strong>(d)</strong> the day on which the arrangement commences.</p><p><strong>15.8</strong> The Health Service must ensure that any individual flexibility arrangement:</p><p><strong>(a)</strong> is about matters that would be permitted matters under section 172 of the Act if the arrangement were an enterprise agreement;</p><p><strong>(b)</strong> does not include any term that would be an unlawful term under section 194 of the Act if the arrangement were an enterprise agreement; and</p><p><strong>(c)</strong> provides for the arrangement to be terminated:</p><p><strong>(i)</strong> by either the Doctor or Health Service giving a specified period of written notice, with the specified period being no more than 28 days; and</p><p><strong>(ii)</strong> at any time by written agreement between the Doctor and Health Service.</p><p><strong>15.9</strong> An individual flexibility arrangement may be expressed to operate for a specified term or while the Doctor is performing a specified role (such as acting in a specified higher</p><p>position). Such an arrangement will terminate on expiry of the specified term, or when the Doctor ceases to perform the specified role, unless terminated earlier on notice or by agreement.</p><p>Plain language terms: IFA, individual flex agreement.</p>',23)])])}const c=t(a,[["render",o]]);export{m as __pageData,c as default};
